def get_region_list():
    """지역 목록 반환"""
    return sorted(SUNSHINE_DATA.keys())

def search_region(keyword: str) -> list:
    """키워드로 지역 검색"""
    keyword = keyword.strip()
    results = []
    for region, data in SUNSHINE_DATA.items():
        if keyword in region or keyword in data["검색키"]:
            results.append(region)
    return results

def get_sunshine(region: str) -> dict:
    """지역 일조시간 데이터 반환"""
    return SUNSHINE_DATA.get(region)

def get_irradiance_kwh(region: str) -> dict:
    """지역 일사량 데이터 반환 (kWh/m²/day 변환 포함)"""
    raw = IRRADIANCE_DATA.get(region)
    if not raw:
        return None
    # kcal/m²/day → kWh/m²/day: ÷ 860
    return {
        "연평균_kWh": round(raw["연평균_kcal"] / 860, 2),
        "월별_kWh": [round(v / 860, 2) for v in raw["월별_kcal"]],
    }
